create table permission
(
    id              bigint auto_increment comment '权限ID'
        primary key,
    parent_id       bigint   default 0                 null comment '父权限ID',
    permission_code varchar(255)                       not null comment '权限编码',
    permission_name varchar(50)                        not null comment '权限名称',
    permission_type tinyint                            not null comment '权限类型：1-菜单，2-按钮，3-接口',
    path            varchar(255)                       null comment '路由路径',
    component       varchar(255)                       null comment '组件路径',
    icon            varchar(50)                        null comment '图标',
    sort_order      int      default 0                 null comment '排序',
    status          tinyint  default 1                 null comment '状态：0-禁用，1-启用',
    deleted         tinyint  default 0                 null comment '是否删除：0-未删除，1-已删除',
    create_time     datetime default CURRENT_TIMESTAMP null comment '创建时间',
    update_time     datetime default CURRENT_TIMESTAMP null on update CURRENT_TIMESTAMP comment '更新时间',
    create_by       bigint                             null comment '创建者',
    update_by       bigint                             null comment '更新者',
    constraint uk_permission_code
        unique (permission_code)
)
    comment '权限表' row_format = DYNAMIC;

create index idx_parent_id
    on permission (parent_id);

create index idx_permission_type
    on permission (permission_type);

create index idx_sort_order
    on permission (sort_order);

create index idx_status
    on permission (status);

